5	export async function loadAudio(url) {
6	  // NOTE: Since the Web Audio API is not available in Node.js, we will need to use the `wavefile` library to obtain the raw audio data.
7	  // For more information, see: https://huggingface.co/docs/transformers.js/guides/node-audio-processing
8	  let wavefile = (await import("wavefile")).default;
9	
10	  // Load audio data
11	  let buffer = Buffer.from(await fetch(url).then((x) => x.arrayBuffer()));
12	
13	  // Read .wav file and convert it to required format
14	  let wav = new wavefile.WaveFile(buffer);
15	  wav.toBitDepth("32f"); // Pipeline expects input as a Float32Array
16	  wav.toSampleRate(16000); // Whisper expects audio with a sampling rate of 16000
17	  let audioData = wav.getSamples();
18	  if (Array.isArray(audioData)) {
19	    if (audioData.length > 1) {
20	      const SCALING_FACTOR = Math.sqrt(2);
21	
22	      // Merge channels (into first channel to save memory)
23	      for (let i = 0; i < audioData[0].length; ++i) {
24	        audioData[0][i] = (SCALING_FACTOR * (audioData[0][i] + audioData[1][i])) / 2;
25	      }
26	    }
27	
28	    // Select first channel
29	    audioData = audioData[0];
30	  }
31	  return audioData;
32	}
