### Step 2 — Add JSDoc typedefs + `ImageTextToTextPipeline` class in `src/pipelines.js`

**Location:** immediately after the closing `}` of `ImageToTextPipeline` (which ends around
line 2005). Insert the following block:

```js
/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text response.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Process an image and text prompt through the model.
 * @param {ImageInput} image The input image.
 * @param {string} text The text prompt (question or instruction) to process alongside the image.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput>} An array of objects containing the generated text.
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using `AutoModelForImageTextToText`. This pipeline accepts
 * an image and a text prompt, and returns generated text. It supports a wide range of
 * vision-language models (VLMs) such as LLaVa, Florence-2, SmolVLM, PaliGemma, and Qwen2-VL.
 *
 * **Example:** Answer a question about an image w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(image, 'How many cats are in this image?');
 * // [{ generated_text: 'There are two cats in the image.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(image, text, generate_kwargs = {}) {
        // Prepare image (read from URL/path/Blob/etc. into a RawImage)
        const preparedImage = (await prepareImages(image))[0];

        // Process image and text together; the processor handles pixel encoding,
        // image-token insertion into the prompt, and tokenization of the text.
        const model_inputs = await this.processor(preparedImage, text);

        // Run generation using all inputs returned by the processor
        const output = await this.model.generate({
            ...model_inputs,
            ...generate_kwargs,
        });

        // Decode generated token ids back into text strings
        const decoded = this.tokenizer.batch_decode(
            /** @type {Tensor} */(output),
            { skip_special_tokens: true },
        );

        return decoded.map(text => ({ generated_text: text.trim() }));
    }
}
```

**Key design notes:**
- Uses `TextImagePipelineConstructorArgs` (the existing typedef that bundles `model`,
  `tokenizer`, and `processor`) — no new typedef needed.
- Calls `this.processor(preparedImage, text)` so the processor handles image tokenization and
  prompt construction together (LLaVa/SmolVLM processors expect `(images, text, kwargs)`).
- Spreads the full `model_inputs` dict into `model.generate()`. For VLMs the processor returns
  `{ input_ids, attention_mask, pixel_values }` — spreading all of them matches how
  `Text2TextGenerationPipeline` calls `model.generate({ ...inputs, ...generate_kwargs })`.
- Intentionally does **not** batch over `pixel_values` the way `ImageToTextPipeline` does,
  because VLM models take `input_ids` as the primary input with `pixel_values` as side channel —
  unlike Vision2Seq encoder-decoder models that take raw pixel batches.
- Returns a flat `ImageTextToTextOutput[]` (not nested), consistent with single-input pipelines
  like `DocumentQuestionAnsweringPipeline`.

