### Step 4 — Create test file `tests/pipelines/test_pipelines_image_text_to_text.js`

The test runner (`tests/test_utils.js`) auto-discovers all files in `tests/pipelines/` via
`fs.readdirSync`, so creating the file is sufficient — no registration step needed.

Follow the exact pattern of `tests/pipelines/test_pipelines_image_to_text.js`:

```js
import { pipeline, ImageTextToTextPipeline } from "../../src/transformers.js";
import { MAX_MODEL_LOAD_TIME, MAX_TEST_EXECUTION_TIME, MAX_MODEL_DISPOSE_TIME, DEFAULT_MODEL_OPTIONS } from "../init.js";
import { load_cached_image } from "../asset_cache.js";

const PIPELINE_ID = "image-text-to-text";

export default () => {
  describe("Image Text to Text", () => {
    // Use a tiny random model compatible with the image-text-to-text architecture.
    // Substitute with the appropriate hf-internal-testing tiny model once identified.
    const model_id = "hf-internal-testing/tiny-random-LlavaForConditionalGeneration";

    /** @type {ImageTextToTextPipeline} */
    let pipe;
    let image;

    beforeAll(async () => {
      pipe = await pipeline(PIPELINE_ID, model_id, DEFAULT_MODEL_OPTIONS);
      image = await load_cached_image("white_image");
    }, MAX_MODEL_LOAD_TIME);

    it("should be an instance of ImageTextToTextPipeline", () => {
      expect(pipe).toBeInstanceOf(ImageTextToTextPipeline);
    });

    describe("batch_size=1", () => {
      it(
        "default",
        async () => {
          const text = "What do you see in this image?";
          const output = await pipe(image, text);
          expect(Array.isArray(output)).toBe(true);
          expect(output[0]).toHaveProperty("generated_text");
          expect(typeof output[0].generated_text).toBe("string");
        },
        MAX_TEST_EXECUTION_TIME,
      );
    });

    afterAll(async () => {
      await pipe.dispose();
    }, MAX_MODEL_DISPOSE_TIME);
  });
};
```

> **Note on test model:** The test uses a tiny random model for fast CI runs. The exact model ID
> `hf-internal-testing/tiny-random-LlavaForConditionalGeneration` should be verified to exist on
> the Hub before committing; if it doesn't, search for an alternative tiny model under
> `hf-internal-testing/` that maps to one of the architectures in
> `MODEL_FOR_IMAGE_TEXT_TO_TEXT_MAPPING_NAMES` (LLaVa, Florence2, SmolVLM, etc.).

