 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Answer a text prompt about an image.
 * @param {ImagePipelineInputs} image The input image.
 * @param {string} text The text prompt to condition generation on.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [generate_kwargs] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput>} An array of objects containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using a `AutoModelForImageTextToText`. This pipeline generates text given an image and a text prompt.
 *
 * **Example:** Answer a question about an image w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(url, 'Describe this image.');
 * // [{ generated_text: 'Two cats are lying on a couch.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(image, text, generate_kwargs = {}) {
        const preparedImage = (await prepareImages(image))[0];
        const model_inputs = await this.processor(preparedImage, text);
        const output = await this.model.generate({ ...model_inputs, ...generate_kwargs });
        const decoded = this.tokenizer.batch_decode(/** @type {import('./utils/tensor.js').Tensor} */(output), {
            skip_special_tokens: true,
        }).map(x => ({ generated_text: x.trim() }));
        return decoded;
    }
}

